int* findSubstring(char* s, char** words, int wordsSize, int* returnSize) {
    *returnSize = 0;
    if (!s || !words || wordsSize == 0) return NULL;
    int wordLen = strlen(words[0]);
    int totalLen = wordLen * wordsSize;
    int sLen = strlen(s);
    if (sLen < totalLen) return NULL;
    int* result = (int*)malloc((sLen - totalLen + 1) * sizeof(int));
    for (int i = 0; i <= sLen - totalLen; i++) {
        int wordCount[wordsSize];
        memset(wordCount, 0, sizeof(wordCount));
        int j = 0;
        while (j < wordsSize) {
            char word[wordLen + 1];
            strncpy(word, s + i + j * wordLen, wordLen);
            word[wordLen] = '\0';
            int found = -1;
            for (int k = 0; k < wordsSize; k++) {
                if (strcmp(word, words[k]) == 0) {
                    found = k;
                    break;
                }
            }
            if (found == -1 || ++wordCount[found] > 1) break;
            j++;
        }
        if (j == wordsSize) result[(*returnSize)++] = i;
    }
    return result;
}
